UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Sierbeplanting (planten in de vollegrond)", "doelorganisme": "Echte meeldauw, Roest", "locatie": "Bedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "75 ml/m²", "maxToepassingen": 3, "interval": "min. 8 dagen", "opmerkingen": ["De gegevens van dit gebruik zijn gebaseerd op het wettelijk gebruiksvoorschrift dat geldig is vanaf 01-01-2019. Raadpleeg voor de complete informatie altijd het wettelijk gebruiksvoorschrift en het etiket.\n\nToepassingsgebied: Sierbeplanting (bedekt)\n\nWerkzaamheid getoetst op: Roest, echte meeldauw.\n\nDosering middel per toepassing:\n600 ml spuitvloeistof/10 m2\n750 ml spuitvloeistof/10 m2 voor planten groter dan 125 cm\n\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen."], "wCodes": ["W1"], "spuitvolumeMin": 600, "spuitvolumeMax": 750, "intervalDagen": 8}, {"gewas": "Sierbeplanting (planten in de vollegrond)", "doelorganisme": "Bladvlekkenziekte, Loofverbruining, Spikkelziekte, Echte meeldauw, Roest", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "75 ml/m²", "maxToepassingen": 3, "interval": "min. 8 dagen", "opmerkingen": ["De gegevens van dit gebruik zijn gebaseerd op het wettelijk gebruiksvoorschrift dat geldig is vanaf 01-01-2019. Raadpleeg voor de complete informatie altijd het wettelijk gebruiksvoorschrift en het etiket.\n\nToepassingsgebied: Sierbeplanting (buiten)\n\nWerkzaamheid getoetst op: Roest, bladvlekkenziekte, echte meeldauw.\n\nDosering middel per toepassing:\n600 ml spuitvloeistof/10 m2\n750 ml spuitvloeistof/10 m2 voor planten groter dan 125 cm\n\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld v